import scala.xml.{XML, Node}

object ConfigService {

  def parseConfig(xmlString: String): Map[String, String] = {
    val xml: Node = XML.loadString(xmlString)
    extractSettings(xml)
  }

  private def extractSettings(node: Node): Map[String, String] = {
    node.child.collect {
      case e: scala.xml.Elem =>
        e.label -> (if (e.text.nonEmpty) e.text else extractSettings(e).mkString(", "))
    }.toMap
  }
}

// Example usage:
val xmlConfig = """
<config>
  <setting name="timeout">30</setting>
  <setting name="retries">5</setting>
  <group>
    <setting name="maxThreads">10</setting>
  </group>
</config>
"""

println(ConfigService.parseConfig(xmlConfig))